1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
12	
13	const sumBasePremiums = (items: any[]): number =>
14	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
15	
16	const addPercent = (amount: number, percent: number): number =>
17	  Math.ceil(amount + (amount * percent) / 100);
18	
19	const quotePremium = (items: any[]): number => {
20	  const base = sumBasePremiums(items);
21	  const withSurcharge = addPercent(base, FIRST_INSURANCE_SURCHARGE_PERCENT);
22	  return withSurcharge + PROCESSING_FEE;
23	};
24	
25	export const runScenario = (scenario: any): unknown => {
26	  const items = scenario.steps[0].items;
27	  return { results: [{ premium: quotePremium(items) }] };
28	};
